from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about an astronaut (or related entities) into a
    single fluent sentence. Handles common astronaut predicates with custom
    phrasing and falls back to a generic “subject predicate object” format.
    """
    if not triples:
        return ""

    parts: list[str] = []
    for t in triples:
        s, p, o = t.subject, t.predicate, t.object

        # Custom phrasing for known predicates
        if p == "birthDate":
            parts.append(f"{s} was born on {o}")
        elif p == "birthPlace":
            parts.append(f"{s} was born in {o}")
        elif p == "birthName":
            parts.append(f"{s}'s birth name is {o}")
        elif p == "nationality":
            parts.append(f"{s} is a {o} astronaut")
        elif p == "mission":
            parts.append(f"{s} flew on {o}")
        elif p == "timeInSpace":
            parts.append(f"{s} spent {o} minutes in space")
        elif p == "occupation":
            parts.append(f"{s} worked as a {o}")
        elif p == "status":
            parts.append(f"{s} is {o}")
        elif p == "deathDate":
            parts.append(f"{s} died on {o}")
        elif p == "deathPlace":
            parts.append(f"{s} died in {o}")
        elif p == "selectedByNasa":
            parts.append(f"{s} was selected by NASA in {o}")
        elif p == "dateOfRetirement":
            parts.append(f"{s} retired in {o}")
        elif p == "title":
            parts.append(f"{s} held the title of {o}")
        elif p == "award" or p == "awards" or p == "ribbonAward":
            parts.append(f"{s} received the {o} award")
        else:
            # Generic fallback
            parts.append(f"{s} {p} {o}")

    # Join the clause fragments into one readable sentence
    sentence = "; ".join(parts) + "."
    return sentence

# EVOLVE-BLOCK-END

